INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Two Cent', 'copy_description', 'This century-old bronze two-cent piece is from the first U.S. coin series to bear IN GOD WE TRUST. The motto appears on the obverse, on a ribbon above the Union Shield. Behind the shield are two crossed arrows and an encircling wreath. The reverse bears 2 CENTS surrounded by two sheaves of wheat tied by a ribbon and UNITED STATES OF AMERICA.');
