INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Three Cent Silver', 'copy_description', 'This century-old silver three-cent piece (or "Trime") is the smallest-denomination silver coin ever issued by the U.S. Mint. Its obverse depicts a Union Shield atop a six-pointed star. UNITED STATES OF AMERICA and the date encircle the design. The reverse features the Roman numeral III surrounded by a large, stylized letter C and 13 stars.');
