INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Capped Bust Half Dime', 'copy_description', 'Struck over 180 years ago, this silver Capped Bust half dime bears John Reich''s classic design. It depicts 13 stars around Liberty in a cloth cap, her curly hair reaching her shoulder where a brooch secures her gown. The reverse bears UNITED STATES OF AMERICA around an American eagle with Union Shield holding an olive branch and three arrows. The denomination 5 c. is below the eagle, with E PLURIBUS UNUM on a banner above.');
