INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Shield Nickel', 'copy_description', 'The classic Shield nickel of 1866-1883 replaced the silver half dimes of 1794-1873. The coin''s obverse depicts a shield and wreath, while the reverse features a large numeral "5" inside a circle of 13 stars above the word CENTS.');
INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Liberty Nickel', 'coin_type', 'Liberty');
