INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Liberty Nickel', 'copy_description', 'When first issued in 1883, Liberty Head Nickels (or "V" nickels) bore just a large Roman numeral "V" for the denomination. So the Mint soon added the word CENTS to stop con artists from gold plating them and passing them off as $5 gold pieces.');
INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Buffalo Nickel', 'coin_type', 'Buffalo');
