INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Buffalo Nickel', 'copy_description', 'Also called the Indian Head nickel, the prized Buffalo nickel is considered the most uniquely American coin. Designed by sculptor James E. Fraser, the obverse depicts a proud Native American. The distinctive reverse features an American bison.');
