INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Capped Bust Half Dollar', 'copy_description', 'Struck over 180 years ago, this 89% silver Capped Bust half dollar bears John Reich''s classic design. It depicts Liberty with long, curling hair and a cloth cap, surrounded by 13 stars and the date. The reverse shows an American eagle with Union Shield, an olive branch and three arrows. A banner above the eagle reads E PLURIBUS UNUM, with 50 c. below and UNITED STATES OF AMERICA surrounding. Inscribed along the coin''s edge is FIFTY CENTS or HALF A DOLLAR.');
