INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Seated Liberty Half Dollar', 'copy_description', 'This 90% silver Liberty Seated half dollar was struck over a century ago. Its classic obverse shows Liberty seated on a rock, holding a Union Shield, a ribbon inscribed LIBERTY and a Liberty cap atop a pole. 13 stars and the date surround her. The reverse depicts an American eagle with Union Shield, an olive branch and three arrows. Encircling the reverse are UNITED STATES OF AMERICA and HALF DOLLAR.');
