INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Seated Liberty Dollar', 'copy_description', 'This century-old 90% silver Liberty Seated dollar bears Christian Gobrecht''s classic design. On the obverse, Liberty sits on a rock surrounded by 13 stars. She holds a Union Shield with banner that reads LIBERTY and a Liberty cap atop a pole. The reverse bears an American eagle with shield, olive branch and 3 arrows. Encircling the eagle are the denomination ONE DOL. and UNITED STATES OF AMERICA.');
INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Trade Dollar', 'coin_type', 'Trade');
