INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Trade Dollar', 'copy_description', 'Designed by William Barber, this 90% silver Trade dollar was struck over a century ago for use in trade with Asia. Its obverse depicts 13 stars around Liberty, who sits on a bale of merchandise by the sea. Her right hand extends an olive branch; her left rests atop a sheaf of wheat and a ribbon inscribed LIBERTY. The reverse shows an American eagle holding three arrows and an olive branch. Below the eagle is 420 GRAINS, 900 FINE., while a banner above reads E PLURIBUS UNUM. UNITED STATES OF AMERICA and TRADE DOLLAR encircle the reverse.');
