INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Eisenhower Dollar', 'copy_description', 'This large dollar coin depicts 34th President Dwight D. Eisenhower, with LIBERTY above and the date below. Next to the portrait is the motto IN GOD WE TRUST. Adapted from the Apollo 11 mission patch, the reverse shows an eagle landing on the moon''s surface, with the earth and E PLURIBUS UNUM above. Encircling the design are UNITED STATES OF AMERICA and ONE DOLLAR.');
INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Susan B Anthony Dollar', 'coin_type', 'Susan B Anthony');
INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Susan B Anthony Dollar', 'denomination', '$1');
INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Susan B Anthony Dollar', 'composition', 'Copper-Nickel Clad');
INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Susan B Anthony Dollar', 'country', 'United States');
INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Susan B Anthony Dollar', 'brand', 'U.S. Mint');
INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Susan B Anthony Dollar', 'copy_description', 'This historic coin is from the America''s first small-size dollar series. Its obverse depicts women''s rights pioneer Susan B. Anthony. Surrounding her portrait are by 13 stars, LIBERTY, IN GOD WE TRUST and the date. Adapted from the Apollo 11 mission patch, the reverse shows an eagle landing on the moon with the earth in the background. Above the eagle are UNITED STATES OF AMERICA and E PLURIBUS UNUM, with ONE DOLLAR below.');
INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Native American Dollar', 'coin_type', 'Native American');
