INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Native American Dollar', 'copy_description', 'This historic Sacagawea dollar honors Lewis and Clark''s young Shoshone guide. The obverse depicts Sacagawea holding her infant son, Jean Baptiste. LIBERTY is inscribed above the pair, with IN GOD WE TRUST on the left and the date at right. The reverse bears a soaring American eagle and E PLURIBUS UNUM. Encircling the reverse are 13 stars, UNITED STATES OF AMERICA and ONE DOLLAR.');
