INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Presidential Dollar', 'copy_description', 'Presidential dollars honor America''s presidents in order of service. Each obverse depicts the featured president, while a common reverse shows the Statue of Liberty and the denomination $1. Edge inscriptions bear each coin''s date, mint mark and the mottoes IN GOD WE TRUST and E PLURIBUS UNUM.');
