INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Gold $2.50 Quarter Eagle', 'copy_description', 'This gold Classic Head quarter eagle was designed by William Kneass. Its obverse is based on John Reich''s classic image of Liberty with flowing hair held by a band inscribed LIBERTY. The date is below, with 13 stars surrounding. The reverse depicts UNITED STATES OF AMERICA and 2 1/2 D. around an American eagle with Union shield, olive branch and three arrows.');
