INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Gold $3', 'copy_description', 'This Indian Princess three-dollar gold piece was designed by James B. Longacre. His classic obverse depicts Liberty in a crown of feathers, on which is a band inscribed LIBERTY. Surrounding her is the inscription UNITED STATES OF AMERICA. The reverse features a wreath of corn, wheat, cotton and tobacco around 3 DOLLARS and the date of issue.');
