INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Gold $10 Eagle', 'copy_description', 'This gold Liberty Head eagle - also called a Coronet Head or Braided Hair eagle - bears Christian Gobrecht''s classic designs. The obverse shows 13 stars around Liberty, who wears a diadem and her long hair in a bun held by a string of beads. On the reverse, a proud American eagle with Union Shield holds an olive branch and three arrows. The denomination TEN D. and UNITED STATES OF AMERICA encircle the reverse.');
INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Gold $20 Double Eagle', 'coin_type', '*** SELECT ***');
