INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Gold $20 Double Eagle', 'copy_description', 'Struck in 90% gold over a century ago, this gold Liberty Head double eagle is larger than a Kennedy half dollar and weighs over 1 troy ounce. It bears James B. Longacre''s classic design. The obverse shows Liberty in a diadem with her long hair up in a bun, surrounded by 13 stars and the date of issue. The reverse bears a stylish heraldic eagle beneath a circle of 13 stars and series of rays. The denomination and UNITED STATES OF AMERICA encircle the design.');
