INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Silver Bullion Coin', 'copy_description', 'Struck in 1 troy ounce of 99.9% pure silver, this hefty American silver eagle bears the series'' original designs. The obverse bears Adolph A. Weinman''s beloved image of Liberty striding to greet the dawn of a new day. She wears a billowing gown of stars and stripes, and carries oak and laurel branches for military and civic glory. John Mercanti''s striking reverse shows a heraldic eagle under a triangle of 13 stars. Encircling the reverse are UNITED STATES OF AMERICA and 1 OZ. FINE SILVER-ONE DOLLAR.');
