INSERT INTO LSCDEVLIBP.SBLLOOKUPT (lookup_name, lookup_key, attr_name, attr_value) VALUES ('category_copy', 'Gold Bullion Coin', 'copy_description', 'This hefty $5 American Buffalo gold bullion coin contains 1/10 ounce of 99.99% pure gold. Only issued in 2008, it''s from the first 24K gold coin series produced by the U.S. Mint. The coin bears James E. Fraser''s iconic Buffalo nickel (or Indian Head) nickel designs. The obverse depicts a proud Native American, while the reverse shows an American bison.');
